import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';

function MyVideosPage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deletingId, setDeletingId] = useState(null);
  const [currentUser, setCurrentUser] = useState(null);
  const navigate = useNavigate();

  const getCurrentUser = () => {
    let username = localStorage.getItem('username');
    if (username) return username;
    
    const token = localStorage.getItem('access');
    if (token) {
      try {
        const payload = JSON.parse(atob(token.split('.')[1]));
        username = payload.username;
        if (username) localStorage.setItem('username', username);
        return username;
      } catch (e) {
        return null;
      }
    }
    return null;
  };

  useEffect(() => {
    const token = localStorage.getItem('access');
    if (!token) {
      navigate('/login');
      return;
    }
    
    const user = getCurrentUser();
    setCurrentUser(user);
    fetchVideos(user);
  }, [navigate]);

  const fetchVideos = async (user) => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get('http://localhost:8000/api/videos/', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      const userVideos = response.data.filter(video => video.uploaded_by_name === user);
      setVideos(userVideos);
      setLoading(false);
    } catch (error) {
      console.error('Ошибка загрузки:', error);
      setLoading(false);
    }
  };

  const handleDelete = async (videoId) => {
    if (!window.confirm('Вы уверены, что хотите удалить это видео?')) return;
    
    setDeletingId(videoId);
    try {
      const token = localStorage.getItem('access');
      await axios.delete(`http://localhost:8000/api/videos/${videoId}/`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      setVideos(videos.filter(v => v.id !== videoId));
      alert('✅ Видео удалено');
    } catch (error) {
      alert('❌ Не удалось удалить видео');
    } finally {
      setDeletingId(null);
    }
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>📼</div>
          <p>Загрузка...</p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 1000, margin: '0 auto', padding: '0 20px' }}>
      <div style={{ marginBottom: 32 }}>
        <h1 style={{ fontSize: 28, fontWeight: 700, marginBottom: 8 }}>📼 Мои видео</h1>
        <p style={{ color: '#6c757d' }}>
          Вы вошли как <span style={{ color: '#4361ee', fontWeight: 500 }}>{currentUser}</span>
        </p>
      </div>
      
      {videos.length === 0 ? (
        <div style={{ textAlign: 'center', padding: 64, background: '#fff', borderRadius: 16 }}>
          <div style={{ fontSize: 64, marginBottom: 20 }}>📭</div>
          <p style={{ fontSize: 18, marginBottom: 24 }}>У вас пока нет загруженных видео</p>
          <Link to="/upload" style={{
            background: '#4361ee',
            color: 'white',
            padding: '12px 24px',
            borderRadius: 12,
            textDecoration: 'none'
          }}>
            + Загрузить видео
          </Link>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {videos.map(video => (
            <div key={video.id} style={{
              background: '#fff',
              borderRadius: 16,
              padding: 16,
              display: 'flex',
              gap: 16,
              alignItems: 'center',
              flexWrap: 'wrap',
              boxShadow: '0 2px 8px rgba(0,0,0,0.04)'
            }}>
              {/* ПРЕВЬЮ - красивая градиентная иконка */}
              <div style={{
                width: 160,
                aspectRatio: '16/9',
                background: `linear-gradient(135deg, ${video.id % 2 === 0 ? '#667eea' : '#764ba2'} 0%, #f093fb 100%)`,
                borderRadius: 12,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 40,
                color: 'white'
              }}>
                🎬
              </div>
              
              {/* Информация */}
              <div style={{ flex: 1 }}>
                <Link to={`/video/${video.id}`} style={{ textDecoration: 'none' }}>
                  <h3 style={{ color: '#1a1a1a', marginBottom: 8, fontSize: 18 }}>{video.title}</h3>
                </Link>
                <p style={{ color: '#6c757d', fontSize: 13, marginBottom: 8 }}>
                  👁️ {video.views || 0} просмотров • 📅 {new Date(video.created_at).toLocaleDateString()}
                </p>
                {video.description && (
                  <p style={{ color: '#6c757d', fontSize: 14 }}>
                    {video.description.length > 80 ? video.description.slice(0, 80) + '...' : video.description}
                  </p>
                )}
              </div>
              
              {/* Кнопка удаления */}
              <button
                onClick={() => handleDelete(video.id)}
                disabled={deletingId === video.id}
                style={{
                  background: '#ef4444',
                  color: 'white',
                  border: 'none',
                  padding: '8px 20px',
                  borderRadius: 8,
                  cursor: deletingId === video.id ? 'not-allowed' : 'pointer',
                  fontSize: 14,
                  fontWeight: 500
                }}
              >
                {deletingId === video.id ? 'Удаление...' : '🗑️ Удалить'}
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default MyVideosPage;
